// // This module implements a 4-bit shift register with parallel load and serial shift capabilities. The shift register should have a 4-bit parallel input (d), a 4-bit output (q), a clock input (clk), a load input (load), and a shift input (shift). The load input has lower priority over the shift input.
module shift_register_4bit (
    input clk,
    input load,
    input shift,
    input [3:0] d,
    output reg [3:0] q
);

always @(posedge clk) begin
    if (load)
        q <= d;
    else if (shift)
        q <= {1'b0, q[3:1]};
end

endmodule
